impl Solution { pub fn longest_subsequence(s: String, k: i32) -> i32 { let (mut black_val, mut black_cnt, mut black_pow) = (0i64, 0, 1i64); for &black_b in s.as_bytes().iter().rev() { if black_b == b'0' { black_cnt += 1; } else if black_pow <= k as i64 { if black_val + black_pow <= k as i64 { black_val += black_pow; black_cnt += 1; } } if black_pow <= k as i64 { black_pow <<= 1; } } black_cnt } }